          "goog.provide('apps.foo.bar.B');",

          "goog.provide('apps.foo.bar.C');"),

      new String[] {

          "var apps = {};apps.foo = {};apps.foo.bar = {}",

          "apps.foo.bar.B = {};",

          "apps.foo.bar.C = {};",

      });

}
